create table dirkspzm32.pps_stueckliste (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    stueckliste_id       number(*, 0) not null enable,
    stueckliste_name     varchar2(255 char) not null enable,
    text1                varchar2(255 char),
    text2                varchar2(255 char),
    text3                varchar2(255 char),
    aktiv                varchar2(1 char) default 'T' not null enable,
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0),
    sl_alternative       number(*, 0) default 0 not null enable
);

alter table dirkspzm32.pps_stueckliste
    add constraint pk_pps_stueckliste
        primary key ( stueckliste_id,
                      sl_alternative,
                      sid )
            using index enable;


